impl PipelineExecutor {
    pub fn new() -> Self {
        Self {
            scorer: Arc::new(MockBackend),
            discord_webhook_url: None,
            disable_external_fetches: false,
        }
    }

    /// Create an executor for tests that should not make external API calls.
    #[cfg(test)]
    pub fn test_executor() -> Self {
