                let name = String::from_utf8_lossy(e.name().as_ref()).to_string();
                match name.as_str() {
                    "entry" => {
                        in_entry = true;
                        title.clear();
                        summary.clear();
                        authors.clear();
                        categories.clear();
                        published.clear();
                        updated.clear();
                        arxiv_id.clear();
                        pdf_url.clear();
                        abs_url.clear();
