        )));
    }

    let body: S2SearchResponse = resp
        .json()
        .await
        .map_err(|e| S2Error::Parse(e.to_string()))?;

    let papers = body
        .data
        .into_iter()
        .filter_map(|r| convert_result(r))
        .collect();

    Ok(papers)
}

