        return 0.0;
    }

    let matches: usize = profile
        .keywords
        .iter()
        .filter(|kw| {
            let kw_lower = kw.to_lowercase();
            content_lower.contains(&kw_lower) || summary_lower.contains(&kw_lower)
        })
        .count();

    (matches as f64) / (profile.keywords.len() as f64)
}

